using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using YourProjectNamespace.Models;

namespace YourProjectNamespace.Controllers
{
    public class ReviewsController : Controller
    {
        private YourDbContext db = new YourDbContext();

        // GET: Reviews
        public ActionResult Index(int productId)
        {
            var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }
    }
}

@model IEnumerable<YourProjectNamespace.Models.Review>

@{
    ViewBag.Title = "Product Reviews";
}

<h2>Product Reviews</h2>

@foreach (var review in Model)
{
    <div class="review">
        <h4>@Html.Encode(review.Title)</h4>
        <p>@Html.Raw(review.Content)</p>
        <p><strong>By:</strong> @Html.Encode(review.Author)</p>
        <hr />
    </div>
}